/**
 * Notification log model for tracking sent notifications.
 *
 * Captures the full delivery lifecycle: recipient, channel, type,
 * timestamp, and delivery status. Used by the NotificationHistoryService
 * to persist an audit trail of all notification attempts.
 */

import type { NotificationChannel, NotificationType, NotificationPriority } from './notification.js';

/**
 * Delivery status of a notification.
 */
export type DeliveryStatus = 'sent' | 'failed';

/**
 * A persisted record of a notification delivery attempt.
 */
export interface NotificationLog {
  /** Unique log entry ID. */
  id: string;
  /** The original notification ID. */
  notificationId: string;
  /** Recipient identifier (email, user ID, webhook URL, etc.). */
  recipient: string;
  /** The delivery channel used. */
  channel: NotificationChannel;
  /** The notification type/category. */
  type: NotificationType;
  /** Priority level of the notification. */
  priority: NotificationPriority;
  /** Subject/title of the notification. */
  subject: string;
  /** Whether delivery succeeded or failed. */
  status: DeliveryStatus;
  /** Error message if delivery failed. */
  error?: string;
  /** When the notification was created. */
  createdAt: Date;
  /** When the delivery attempt completed. */
  deliveredAt: Date;
  /** Optional metadata from the original notification. */
  metadata?: Record<string, unknown>;
}

/**
 * Query filters for searching notification history.
 */
export interface NotificationLogQuery {
  /** Filter by recipient. */
  recipient?: string;
  /** Filter by notification type. */
  type?: NotificationType;
  /** Filter by delivery channel. */
  channel?: NotificationChannel;
  /** Filter by delivery status. */
  status?: DeliveryStatus;
  /** Filter by date range start (inclusive). */
  from?: Date;
  /** Filter by date range end (inclusive). */
  to?: Date;
}

/**
 * Repository for notification log data access.
 *
 * Extends BaseRepository with notification-log-specific query methods.
 * Depends on the Database utility layer for storage.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLog } from '../models/notification-log.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';
import type { DeliveryStatus } from '../models/notification-log.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    const log: NotificationLog = {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      type: record['type'] as NotificationType,
      priority: record['priority'] as string as NotificationLog['priority'],
      subject: record['subject'] as string,
      status: record['status'] as DeliveryStatus,
      createdAt: new Date(record['createdAt'] as string),
      deliveredAt: new Date(record['deliveredAt'] as string),
    };
    if (record['error']) {
      log.error = record['error'] as string;
    }
    if (record['metadata']) {
      log.metadata = JSON.parse(record['metadata'] as string) as Record<string, unknown>;
    }
    return log;
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    const record: DatabaseRecord = {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      priority: entity.priority,
      subject: entity.subject,
      status: entity.status,
      createdAt: entity.createdAt.toISOString(),
      deliveredAt: entity.deliveredAt.toISOString(),
    };
    if (entity.error) {
      record['error'] = entity.error;
    }
    if (entity.metadata) {
      record['metadata'] = JSON.stringify(entity.metadata);
    }
    return record;
  }

  /**
   * Find all logs for a specific recipient.
   */
  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  /**
   * Find all logs for a specific notification type.
   */
  findByType(type: NotificationType): NotificationLog[] {
    return this.findAll((log) => log.type === type);
  }

  /**
   * Find all logs for a specific channel.
   */
  findByChannel(channel: NotificationChannel): NotificationLog[] {
    return this.findAll((log) => log.channel === channel);
  }

  /**
   * Find all logs with a specific delivery status.
   */
  findByStatus(status: DeliveryStatus): NotificationLog[] {
    return this.findAll((log) => log.status === status);
  }

  /**
   * Find all logs within a date range (based on deliveredAt).
   */
  findByDateRange(from: Date, to: Date): NotificationLog[] {
    return this.findAll(
      (log) => log.deliveredAt >= from && log.deliveredAt <= to,
    );
  }
}

/**
 * Notification history service — tracks all sent and failed notifications.
 *
 * Integrates with the existing notification flow by subscribing to
 * notification:sent and notification:failed events on the EventBus.
 * Every delivery attempt is persisted as a NotificationLog entry
 * in the repository.
 *
 * Provides query methods for searching notification history by
 * recipient, type, channel, status, and date range.
 *
 * Depends on:
 * - EventBus for receiving notification delivery events
 * - NotificationLogRepository for persistence
 */

import type { EventBus } from '../events/event-bus.js';
import type { NotificationSentEvent, NotificationFailedEvent } from '../events/event-types.js';
import type { NotificationLog, NotificationLogQuery, DeliveryStatus } from '../models/notification-log.js';
import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `log-${String(nextLogId++).padStart(4, '0')}`;
}

/** Reset the log ID counter (useful for testing). */
export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(
    private eventBus: EventBus,
    private repository: NotificationLogRepository,
  ) {
    this.registerHandlers();
  }

  /**
   * Subscribe to notification delivery events on the EventBus.
   */
  private registerHandlers(): void {
    this.eventBus.on<NotificationSentEvent>('notification:sent', (event) => {
      this.logNotification(event.payload, event.result, 'sent');
    });

    this.eventBus.on<NotificationFailedEvent>('notification:failed', (event) => {
      this.logNotification(event.payload, event.result, 'failed');
    });
  }

  /**
   * Persist a notification delivery attempt to the repository.
   */
  private logNotification(
    payload: NotificationSentEvent['payload'],
    result: NotificationSentEvent['result'],
    status: DeliveryStatus,
  ): void {
    const log: NotificationLog = {
      id: generateLogId(),
      notificationId: payload.id,
      recipient: payload.recipient,
      channel: payload.channel,
      type: payload.type,
      priority: payload.priority,
      subject: payload.subject,
      status,
      createdAt: payload.createdAt,
      deliveredAt: result.deliveredAt,
      metadata: payload.metadata,
    };

    if (result.error) {
      log.error = result.error;
    }

    this.repository.save(log);
    this.logger.info(
      `Logged notification ${payload.id} [${status}] to ${payload.recipient} via ${payload.channel}`,
    );
  }

  /**
   * Query notification history with flexible filters.
   * All filters are optional and combined with AND logic.
   */
  query(filters: NotificationLogQuery): NotificationLog[] {
    return this.repository.findAll((log) => {
      if (filters.recipient && log.recipient !== filters.recipient) {
        return false;
      }
      if (filters.type && log.type !== filters.type) {
        return false;
      }
      if (filters.channel && log.channel !== filters.channel) {
        return false;
      }
      if (filters.status && log.status !== filters.status) {
        return false;
      }
      if (filters.from && log.deliveredAt < filters.from) {
        return false;
      }
      if (filters.to && log.deliveredAt > filters.to) {
        return false;
      }
      return true;
    });
  }

  /**
   * Get all notification logs for a specific recipient.
   */
  getHistoryForRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Get all notification logs for a specific type.
   */
  getHistoryByType(type: NotificationLogQuery['type']!): NotificationLog[] {
    return this.repository.findByType(type!);
  }

  /**
   * Get all notification logs within a date range.
   */
  getHistoryByDateRange(from: Date, to: Date): NotificationLog[] {
    return this.repository.findByDateRange(from, to);
  }

  /**
   * Get a specific notification log by its ID.
   */
  getLogById(id: string): NotificationLog | undefined {
    return this.repository.findById(id);
  }

  /**
   * Get the total count of logged notifications.
   */
  getLogCount(): number {
    return this.repository.count();
  }
}

