import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import { Database } from '../../src/utils/database.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';
import type { NotificationPayload, NotificationResult } from '../../src/models/notification.js';

function makeOrderCreatedEvent(overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent {
  return {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
      status: 'pending',
      createdAt: new Date('2026-01-15T10:00:00Z'),
      updatedAt: new Date('2026-01-15T10:00:00Z'),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date('2026-01-15T10:00:00Z'),
    ...overrides,
  };
}

function makeStatusChangedEvent(overrides?: Partial<OrderStatusChangedEvent>): OrderStatusChangedEvent {
  return {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 20,
      status: 'confirmed',
      createdAt: new Date('2026-01-15T10:00:00Z'),
      updatedAt: new Date('2026-01-15T10:00:00Z'),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date('2026-01-15T10:00:00Z'),
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let historyService: NotificationHistoryService;
  let repository: NotificationLogRepository;
  let db: Database;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    eventBus = new EventBus();
    db = new Database();
    repository = new NotificationLogRepository(db);
    notificationService = new NotificationService(eventBus);
    historyService = new NotificationHistoryService(eventBus, repository);
    emailAdapter = new EmailAdapter();
    notificationService.registerAdapter(emailAdapter);
    resetNotificationIdCounter();
    resetLogIdCounter();
  });

  describe('logging sent notifications', () => {
    it('should log a notification when it is sent successfully', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      expect(historyService.getLogCount()).toBe(1);
      const logs = historyService.getHistoryForRecipient('alice@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0]?.notificationId).toBe('notif-0001');
      expect(logs[0]?.recipient).toBe('alice@example.com');
      expect(logs[0]?.channel).toBe('email');
      expect(logs[0]?.type).toBe('order:confirmation');
      expect(logs[0]?.status).toBe('sent');
      expect(logs[0]?.subject).toContain('Order Confirmation');
      expect(logs[0]?.error).toBeUndefined();
    });

    it('should log multiple notifications', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent());

      expect(historyService.getLogCount()).toBe(2);
    });

    it('should generate sequential log IDs', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent());

      const log1 = historyService.getLogById('log-0001');
      const log2 = historyService.getLogById('log-0002');
      expect(log1).toBeDefined();
      expect(log2).toBeDefined();
    });
  });

  describe('logging failed notifications', () => {
    it('should log a notification when delivery fails', async () => {
      const payload: NotificationPayload = {
        id: 'notif-fail-1',
        type: 'order:confirmation',
        channel: 'email',
        recipient: 'bob@example.com',
        subject: 'Test',
        body: 'Test body',
        priority: 'normal',
        createdAt: new Date('2026-01-15T10:00:00Z'),
      };
      const result: NotificationResult = {
        notificationId: 'notif-fail-1',
        channel: 'email',
        success: false,
        error: 'SMTP connection refused',
        deliveredAt: new Date('2026-01-15T10:00:01Z'),
      };

      await eventBus.emit({
        type: 'notification:failed',
        payload,
        result,
        timestamp: new Date(),
      });

      expect(historyService.getLogCount()).toBe(1);
      const logs = historyService.getHistoryForRecipient('bob@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('failed');
      expect(logs[0]?.error).toBe('SMTP connection refused');
    });
  });

  describe('querying by recipient', () => {
    it('should return logs for a specific recipient', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(
        makeOrderCreatedEvent({
          order: {
            id: 'order-2',
            userId: 'user-2',
            items: [{ productId: 'p1', name: 'Gadget', quantity: 1, unitPrice: 15 }],
            total: 15,
            status: 'pending',
            createdAt: new Date(),
            updatedAt: new Date(),
          },
          user: {
            id: 'user-2',
            name: 'Bob',
            email: 'bob@example.com',
            role: 'member',
            createdAt: new Date(),
            updatedAt: new Date(),
          },
        }),
      );

      expect(historyService.getHistoryForRecipient('alice@example.com')).toHaveLength(1);
      expect(historyService.getHistoryForRecipient('bob@example.com')).toHaveLength(1);
      expect(historyService.getHistoryForRecipient('charlie@example.com')).toHaveLength(0);
    });
  });

  describe('querying by type', () => {
    it('should return logs for a specific notification type', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent());

      const confirmations = historyService.getHistoryByType('order:confirmation');
      expect(confirmations).toHaveLength(1);
      expect(confirmations[0]?.type).toBe('order:confirmation');

      const updates = historyService.getHistoryByType('order:status-update');
      expect(updates).toHaveLength(1);
      expect(updates[0]?.type).toBe('order:status-update');
    });
  });

  describe('querying by date range', () => {
    it('should return logs within a date range', async () => {
      const earlyPayload: NotificationPayload = {
        id: 'notif-early',
        type: 'order:confirmation',
        channel: 'email',
        recipient: 'alice@example.com',
        subject: 'Early',
        body: 'Early notification',
        priority: 'normal',
        createdAt: new Date('2026-01-10T10:00:00Z'),
      };
      const latePayload: NotificationPayload = {
        id: 'notif-late',
        type: 'order:confirmation',
        channel: 'email',
        recipient: 'alice@example.com',
        subject: 'Late',
        body: 'Late notification',
        priority: 'normal',
        createdAt: new Date('2026-01-20T10:00:00Z'),
      };

      await eventBus.emit({
        type: 'notification:sent',
        payload: earlyPayload,
        result: {
          notificationId: 'notif-early',
          channel: 'email',
          success: true,
          deliveredAt: new Date('2026-01-10T10:00:01Z'),
        },
        timestamp: new Date('2026-01-10T10:00:01Z'),
      });
      await eventBus.emit({
        type: 'notification:sent',
        payload: latePayload,
        result: {
          notificationId: 'notif-late',
          channel: 'email',
          success: true,
          deliveredAt: new Date('2026-01-20T10:00:01Z'),
        },
        timestamp: new Date('2026-01-20T10:00:01Z'),
      });

      const ranged = historyService.getHistoryByDateRange(
        new Date('2026-01-09T00:00:00Z'),
        new Date('2026-01-15T00:00:00Z'),
      );
      expect(ranged).toHaveLength(1);
      expect(ranged[0]?.notificationId).toBe('notif-early');
    });
  });

  describe('flexible query', () => {
    it('should support combined filters', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent());

      const results = historyService.query({
        recipient: 'alice@example.com',
        type: 'order:confirmation',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('order:confirmation');
    });

    it('should return all logs when no filters are provided', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent());

      const results = historyService.query({});
      expect(results).toHaveLength(2);
    });

    it('should filter by status', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      // Emit a failed notification directly
      await eventBus.emit({
        type: 'notification:failed',
        payload: {
          id: 'notif-fail',
          type: 'order:confirmation',
          channel: 'email',
          recipient: 'fail@example.com',
          subject: 'Fail',
          body: 'Failed',
          priority: 'normal',
          createdAt: new Date(),
        },
        result: {
          notificationId: 'notif-fail',
          channel: 'email',
          success: false,
          error: 'Transport error',
          deliveredAt: new Date(),
        },
        timestamp: new Date(),
      });

      const sent = historyService.query({ status: 'sent' });
      expect(sent).toHaveLength(1);

      const failed = historyService.query({ status: 'failed' });
      expect(failed).toHaveLength(1);
      expect(failed[0]?.error).toBe('Transport error');
    });

    it('should filter by channel', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const emailLogs = historyService.query({ channel: 'email' });
      expect(emailLogs).toHaveLength(1);

      const webhookLogs = historyService.query({ channel: 'webhook' });
      expect(webhookLogs).toHaveLength(0);
    });

    it('should filter by date range in query', async () => {
      const payload: NotificationPayload = {
        id: 'notif-dated',
        type: 'order:confirmation',
        channel: 'email',
        recipient: 'alice@example.com',
        subject: 'Dated',
        body: 'Dated notification',
        priority: 'normal',
        createdAt: new Date('2026-02-01T10:00:00Z'),
      };

      await eventBus.emit({
        type: 'notification:sent',
        payload,
        result: {
          notificationId: 'notif-dated',
          channel: 'email',
          success: true,
          deliveredAt: new Date('2026-02-01T10:00:01Z'),
        },
        timestamp: new Date('2026-02-01T10:00:01Z'),
      });

      const inRange = historyService.query({
        from: new Date('2026-01-31T00:00:00Z'),
        to: new Date('2026-02-02T00:00:00Z'),
      });
      expect(inRange).toHaveLength(1);

      const outOfRange = historyService.query({
        from: new Date('2026-03-01T00:00:00Z'),
        to: new Date('2026-03-31T00:00:00Z'),
      });
      expect(outOfRange).toHaveLength(0);
    });
  });

  describe('integration with notification service', () => {
    it('should automatically log notifications sent through the full flow', async () => {
      // This tests the full integration: event → NotificationService → adapter → EventBus → HistoryService
      await eventBus.emit(makeOrderCreatedEvent());

      // Verify notification was sent by the notification service
      expect(notificationService.getNotificationCount()).toBe(1);

      // Verify it was also logged by the history service
      expect(historyService.getLogCount()).toBe(1);

      const logs = historyService.query({ type: 'order:confirmation' });
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('sent');
      expect(logs[0]?.recipient).toBe('alice@example.com');
    });

    it('should capture metadata from the original notification', async () => {
      const payload: NotificationPayload = {
        id: 'notif-meta',
        type: 'order:confirmation',
        channel: 'email',
        recipient: 'alice@example.com',
        subject: 'With Metadata',
        body: 'Body',
        priority: 'high',
        createdAt: new Date(),
        metadata: { orderId: 'order-99', source: 'test' },
      };

      await eventBus.emit({
        type: 'notification:sent',
        payload,
        result: {
          notificationId: 'notif-meta',
          channel: 'email',
          success: true,
          deliveredAt: new Date(),
        },
        timestamp: new Date(),
      });

      const logs = historyService.getHistoryForRecipient('alice@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0]?.metadata).toEqual({ orderId: 'order-99', source: 'test' });
      expect(logs[0]?.priority).toBe('high');
    });
  });
});

